function escapeHtml(value) {
  return String(value ?? '')
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#39;');
}

function maskToken(value, head = 10, tail = 6) {
  const text = String(value || '');
  if (!text) return '';
  if (text.length <= head + tail + 3) return text;
  return `${text.slice(0, head)}...${text.slice(-tail)}`;
}

function buildFormUrlEncoded(payload) {
  return Object.entries(payload || {})
    .map(([key, value]) => `${encodeURIComponent(String(key || ''))}=${encodeURIComponent(String(value ?? ''))}`)
    .join('&');
}

function appendQueryParams(url, payload) {
  const query = buildFormUrlEncoded(payload);
  if (!query) return String(url || '');
  return String(url || '').includes('?')
    ? `${String(url)}&${query}`
    : `${String(url)}?${query}`;
}

async function exchangeToken(appId, secretKey, code) {
  const form = buildFormUrlEncoded({
    app_id: String(appId || ''),
    code: String(code || ''),
    grant_type: 'authorization_code',
  });

  const response = await fetch('https://oauth.zaloapp.com/v4/oa/access_token', {
    method: 'POST',
    headers: {
      'Content-Type': 'application/x-www-form-urlencoded',
      secret_key: String(secretKey || ''),
    },
    body: form,
  });

  const raw = await response.text();
  let payload;
  try {
    payload = JSON.parse(raw);
  } catch {
    payload = { raw };
  }

  return {
    status: response.status,
    ok: response.ok && Boolean(payload.access_token),
    payload,
  };
}

async function syncRefreshWorkflow(refreshWebhookUrl, refreshToken) {
  const url = appendQueryParams(refreshWebhookUrl, {
    refresh_token: String(refreshToken || ''),
    force: '1',
    source: 'auth_callback',
  });

  const response = await fetch(url, { method: 'GET' });
  return {
    status: response.status,
    ok: response.ok,
    body: await response.text(),
  };
}

const input = $input.first().json || {};
const query = input.query || {};
const code = String(query.code || '').trim();
const errorCode = String(query.error || query.error_code || '').trim();
const errorDescription = String(query.error_description || query.error_reason || '').trim();
const appId = String($vars.ZALO_APP_ID || '1450975846052622442').trim();
const secretKey = String($vars.ZALO_OA_SECRET_KEY || $vars.ZALO_APP_SECRET || '').trim();
const redirectUrl = String(input.webhookUrl || '').trim();
const refreshWebhookUrl = 'https://n214.fastn8n.id.vn/webhook/zalo-oa-refresh-token';

let ok = false;
let title = 'CaloTrack Zalo OA auth callback';
let summary = '';
let exchange = null;
let handoff = null;
let accessToken = '';
let refreshToken = '';
let expiresIn = 0;
let expiresAt = '';

if (errorCode) {
  title = 'Zalo OA permission failed';
  summary = `Zalo returned ${errorCode}${errorDescription ? ` - ${errorDescription}` : ''}.`;
} else if (!code) {
  title = 'Missing authorization code';
  summary = 'No code was found in the callback URL.';
} else if (!secretKey) {
  title = 'Missing Zalo secret in n8n';
  summary = 'Set ZALO_OA_SECRET_KEY or ZALO_APP_SECRET in n8n variables before exchanging the code.';
} else {
  exchange = await exchangeToken(appId, secretKey, code);
  const payload = exchange.payload || {};
  accessToken = String(payload.access_token || payload.accessToken || '').trim();
  refreshToken = String(payload.refresh_token || payload.refreshToken || '').trim();
  expiresIn = Number(payload.expires_in || payload.expires || 0) || 0;
  expiresAt = expiresIn > 0 ? new Date(Date.now() + (expiresIn * 1000)).toISOString() : '';
  ok = Boolean(exchange.ok && accessToken);

  if (!ok) {
    title = 'Zalo OA token exchange failed';
    summary = `Zalo returned HTTP ${exchange.status}. Check the callback URL, OA permission scope, and the current app secret.`;
  } else {
    title = 'Zalo OA token ready';
    summary = 'The authorization code was exchanged successfully.';
    if (refreshToken) {
      handoff = await syncRefreshWorkflow(refreshWebhookUrl, refreshToken);
      if (handoff.ok) {
        summary += ' The new refresh token was handed off to the auto-refresh workflow.';
      } else {
        summary += ' Auto-refresh handoff failed, so the refresh workflow may still need manual bootstrap.';
      }
    }
  }
}

const responseJson = {
  ok,
  title,
  summary,
  app_id: appId,
  redirect_url: redirectUrl,
  access_token_masked: maskToken(accessToken),
  refresh_token_masked: maskToken(refreshToken),
  expires_in: expiresIn,
  expires_at: expiresAt,
  exchange_http_status: exchange?.status || null,
  handoff_http_status: handoff?.status || null,
};

const html = `<!DOCTYPE html>
<html lang="vi">
<head>
  <meta charset="utf-8" />
  <meta name="viewport" content="width=device-width, initial-scale=1" />
  <title>${escapeHtml(title)}</title>
  <style>
    body { font-family: Inter, Arial, sans-serif; background: #f4fbfa; color: #17203a; padding: 40px 20px; }
    .card { max-width: 920px; margin: 0 auto; background: #ffffff; border: 1px solid #d7ece8; border-radius: 24px; padding: 28px; box-shadow: 0 20px 60px rgba(23, 32, 58, 0.08); }
    .badge { display: inline-block; padding: 6px 12px; border-radius: 999px; font-size: 12px; letter-spacing: 0.12em; text-transform: uppercase; background: ${ok ? '#d9f5ef' : '#fff3e8'}; color: ${ok ? '#0f766e' : '#b45309'}; }
    h1 { margin: 16px 0 8px; font-size: 34px; }
    p { line-height: 1.6; color: #4f5d78; }
    pre { white-space: pre-wrap; word-break: break-word; background: #f7fafc; border: 1px solid #dde6f0; border-radius: 16px; padding: 16px; font-size: 13px; overflow: auto; }
    .grid { display: grid; gap: 14px; grid-template-columns: repeat(auto-fit, minmax(260px, 1fr)); margin-top: 22px; }
    .panel { background: #fbfdff; border: 1px solid #e8eef5; border-radius: 18px; padding: 16px; }
    .panel h2 { margin: 0 0 12px; font-size: 14px; letter-spacing: 0.08em; text-transform: uppercase; color: #0f766e; }
    .mono { font-family: Consolas, monospace; }
  </style>
</head>
<body>
  <div class="card">
    <span class="badge">${ok ? 'ready' : 'needs action'}</span>
    <h1>${escapeHtml(title)}</h1>
    <p>${escapeHtml(summary)}</p>
    <div class="grid">
      <div class="panel">
        <h2>Token state</h2>
        <pre class="mono">access_token=${escapeHtml(maskToken(accessToken))}
refresh_token=${escapeHtml(maskToken(refreshToken))}
expires_at=${escapeHtml(expiresAt)}</pre>
      </div>
      <div class="panel">
        <h2>Workflow handoff</h2>
        <pre class="mono">refresh_workflow=${escapeHtml(refreshWebhookUrl)}
exchange_http_status=${escapeHtml(exchange?.status || '')}
handoff_http_status=${escapeHtml(handoff?.status || '')}</pre>
      </div>
    </div>
    <div class="panel" style="margin-top: 18px;">
      <h2>Response JSON</h2>
      <pre class="mono">${escapeHtml(JSON.stringify(responseJson, null, 2))}</pre>
    </div>
  </div>
</body>
</html>`;

return [{ json: { ...responseJson, html } }];
